import{_ as t,o as a,c as _,ai as r}from"./chunks/framework.B1-4-q7d.js";const f=JSON.parse('{"title":"空中力量再扩容 玉林玉州区智慧农业迈上新台阶","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"空中力量再扩容 玉林玉州区智慧农业迈上新台阶","date":"2026-04-29T00:00:00.000Z","source":"农业农村部智慧农业专题","category":"news","link":"https://www.moa.gov.cn/ztzl/zhnyzxd/xydt/202604/t20260410_6483153.htm","summary":"中新网广西新闻4月4日电(杨伊静 卢旭林)随着2026年第一批农机购置补贴工作顺利落地,广西玉林市玉州区新增植保无人驾驶航空器33台,全区拥有量由此前的30台跃升至63台,实现翻番式增长,助力玉州智慧农业迈上新台阶。\\n这一跨越式发展,得益于玉州区农机中心精准有力的政策引导——通过优化补贴办理流程、加大宣传推广力度,充分激发了农业经营主体的购机热情,推动高效智能装备加速普及。\\n图为无人机正在作业。...\\n","contentHash":"8d36fc2fd247d0dd1967b66ad0a036da","tags":["智慧农业","行业资讯"]},"headers":[],"relativePath":"news/2026-04-29-空中力量再扩容-玉林玉州区智慧农业迈上新台阶.md","filePath":"news/2026-04-29-空中力量再扩容-玉林玉州区智慧农业迈上新台阶.md"}'),n={name:"news/2026-04-29-空中力量再扩容-玉林玉州区智慧农业迈上新台阶.md"};function s(o,e,d,p,l,c){return a(),_("div",null,[...e[0]||(e[0]=[r('<h1 id="空中力量再扩容-玉林玉州区智慧农业迈上新台阶" tabindex="-1">空中力量再扩容 玉林玉州区智慧农业迈上新台阶 <a class="header-anchor" href="#空中力量再扩容-玉林玉州区智慧农业迈上新台阶" aria-label="Permalink to &quot;空中力量再扩容 玉林玉州区智慧农业迈上新台阶&quot;">​</a></h1><blockquote><p>来源: <a href="https://www.moa.gov.cn/ztzl/zhnyzxd/xydt/202604/t20260410_6483153.htm" target="_blank" rel="noreferrer">农业农村部智慧农业专题</a><br> 日期: 2026-04-29 摘要: 中新网广西新闻4月4日电(杨伊静 卢旭林)随着2026年第一批农机购置补贴工作顺利落地,广西玉林市玉州区新增植保无人驾驶航空器33台,全区拥有量由此前的30台跃升至63台,实现翻番式增长,助力玉州智慧农业迈上新台阶。 这一跨越式发展,得益于玉州区农机中心精准有力的政策引导——通过优化补贴办理流程、加大宣传推广力度,充分激发了农业经营主体的购机热情,推动高效智能装备加速普及。 图为无人机正在作业。...</p></blockquote><p>这一跨越式发展,得益于玉州区农机中心精准有力的政策引导——通过优化补贴办理流程、加大宣传推广力度,充分激发了农业经营主体的购机热情,推动高效智能装备加速普及。</p><p>此次新增的33台无人机为最新智能机型,具备精准施药、自动规划航线、智能避障等功能,单机作业效率较传统人工提升数十倍。</p><p>目前,无人机应用已从单一的植保环节向耕、种、管、收全链条延伸——在播种环节可实施精准飞播,在田间管理阶段实现高效施肥与病虫害统防统治,在收获前还可辅助监测作物成熟度,真正实现“一机多用、全程赋能”。</p><p>玉州区63台无人机年作业能力预计可覆盖超过20万亩次农田管护,在水稻、果蔬等主要农作物的生产中发挥主力军作用,有效破解传统农业“用工难、效率低”的瓶颈。无人机精准作业大幅减少农药化肥施用量,降低农业面源污染,实现经济效益与生态效益的双赢。</p><p>目前,玉州区正加快农机智能化监管步伐,已在各类农机具上安装终端远程监控系统设备共计105台,构建起覆盖“耕、种、管、收、烘、育”全环节的智慧监管网络,为农机精准调度、作业质量追溯、安全高效生产提供了有力保障。</p><p>下一步,玉州区将持续做好补贴政策落实与服务保障工作,加强机手技能培训和安全监管,以“空中力量”的持续壮大助推现代农业高质量发展。(完)</p><p><a href="https://www.moa.gov.cn/ztzl/zhnyzxd/xydt/202604/t20260410_6483153.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',9)])])}const h=t(n,[["render",s]]);export{f as __pageData,h as default};
